import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.Pywvta2k.js";const y=JSON.parse('{"title":"下经三十四卦与人体对应","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/09-医易同源/07-六十四卦人体全对应/02-下经三十四卦与人体.md","filePath":"tcm-data/09-医易同源/07-六十四卦人体全对应/02-下经三十四卦与人体.md","lastUpdated":1781084559000}'),n={name:"tcm-data/09-医易同源/07-六十四卦人体全对应/02-下经三十四卦与人体.md"};function d(s,t,o,g,i,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="下经三十四卦与人体对应" tabindex="-1">下经三十四卦与人体对应 <a class="header-anchor" href="#下经三十四卦与人体对应" aria-label="Permalink to &quot;下经三十四卦与人体对应&quot;">​</a></h1><blockquote><p>从咸卦到未济卦——人伦之始，杂病之源 《易经》下经以人道为主，对应人体的具体疾病和人际情感</p></blockquote><hr><h2 id="概览-下经三十四卦" tabindex="-1">概览：下经三十四卦 <a class="header-anchor" href="#概览-下经三十四卦" aria-label="Permalink to &quot;概览：下经三十四卦&quot;">​</a></h2><p><strong>咸恒遁兮及大壮，晋与明夷家人睽。 蹇解损益夬姤萃，升困井革鼎震继。 艮渐归妹丰旅巽，兑涣节兮中孚至。 小过既济兼未济，是为下经三十四。</strong></p><hr><h2 id="一、咸恒——夫妇之道-情感与健康" tabindex="-1">一、咸恒——夫妇之道（情感与健康） <a class="header-anchor" href="#一、咸恒——夫妇之道-情感与健康" aria-label="Permalink to &quot;一、咸恒——夫妇之道（情感与健康）&quot;">​</a></h2><h3 id="䷞咸——山上有泽-感应" tabindex="-1">䷞咸——山上有泽（感应） <a class="header-anchor" href="#䷞咸——山上有泽-感应" aria-label="Permalink to &quot;䷞咸——山上有泽（感应）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>卦象</strong></td><td style="text-align:left;">艮☶下兑☱上——少男少女，感应之始</td></tr><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">⭐ <strong>心肾相交的基础——&quot;感&quot;</strong></td></tr><tr><td style="text-align:left;"><strong>对应中医</strong></td><td style="text-align:left;"><strong>心肾不交→失眠、烦躁</strong>（普明）</td></tr><tr><td style="text-align:left;"><strong>爻辞</strong></td><td style="text-align:left;">&quot;咸其辅颊舌&quot;——从脚到口的感应路线，对应中医经络循行</td></tr><tr><td style="text-align:left;"><strong>病理</strong></td><td style="text-align:left;">咸卦失常→心肾不感→水火不交</td></tr><tr><td style="text-align:left;"><strong>普明</strong></td><td style="text-align:left;">潮热失眠、入睡困难→<strong>心肾不交之&quot;咸卦&quot;失常</strong></td></tr></tbody></table><h3 id="䷟恒——雷风恒-持久" tabindex="-1">䷟恒——雷风恒（持久） <a class="header-anchor" href="#䷟恒——雷风恒-持久" aria-label="Permalink to &quot;䷟恒——雷风恒（持久）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">巽☴下震☳上——长女长男</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">肝（震）与胆（巽）——<strong>肝胆相照，恒久之道</strong></td></tr><tr><td style="text-align:left;"><strong>对应</strong></td><td style="text-align:left;">健康需要恒心——养生贵在坚持</td></tr></tbody></table><hr><h2 id="二、遁大壮晋明夷——进退与伤病" tabindex="-1">二、遁大壮晋明夷——进退与伤病 <a class="header-anchor" href="#二、遁大壮晋明夷——进退与伤病" aria-label="Permalink to &quot;二、遁大壮晋明夷——进退与伤病&quot;">​</a></h2><h3 id="䷠遁——天下有山-退避" tabindex="-1">䷠遁——天下有山（退避） <a class="header-anchor" href="#䷠遁——天下有山-退避" aria-label="Permalink to &quot;䷠遁——天下有山（退避）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">艮☶下乾☰上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">阳气（乾）被阻（艮）——<strong>正气退、邪气进</strong></td></tr><tr><td style="text-align:left;"><strong>对应</strong></td><td style="text-align:left;">慢性病、正虚邪恋</td></tr></tbody></table><h3 id="䷡大壮——雷在天上-壮盛" tabindex="-1">䷡大壮——雷在天上（壮盛） <a class="header-anchor" href="#䷡大壮——雷在天上-壮盛" aria-label="Permalink to &quot;䷡大壮——雷在天上（壮盛）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">乾☰下震☳上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">肝气（震）壮盛——<strong>肝阳上亢的初始</strong></td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;">情绪易怒、血压升高、头痛</td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">镇肝熄风汤</td></tr></tbody></table><h3 id="䷢晋——明出地上-前进" tabindex="-1">䷢晋——明出地上（前进） <a class="header-anchor" href="#䷢晋——明出地上-前进" aria-label="Permalink to &quot;䷢晋——明出地上（前进）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">坤☷下离☲上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">心火（离）得脾土（坤）助——<strong>气血充盈，面色光润</strong></td></tr></tbody></table><h3 id="䷣明夷——明入地中-受伤" tabindex="-1">䷣明夷——明入地中（受伤） <a class="header-anchor" href="#䷣明夷——明入地中-受伤" aria-label="Permalink to &quot;䷣明夷——明入地中（受伤）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">离☲下坤☷上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">⭐ <strong>心火（离）陷入脾土（坤）——郁热内伏</strong></td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;">内热、烦躁、面色暗沉</td></tr><tr><td style="text-align:left;"><strong>普光</strong></td><td style="text-align:left;">口渴不贪凉+面色暗沉→明夷卦——热被湿土所困</td></tr></tbody></table><hr><h2 id="三、家人睽蹇解——家庭与人际-情绪致病" tabindex="-1">三、家人睽蹇解——家庭与人际（情绪致病） <a class="header-anchor" href="#三、家人睽蹇解——家庭与人际-情绪致病" aria-label="Permalink to &quot;三、家人睽蹇解——家庭与人际（情绪致病）&quot;">​</a></h2><h3 id="䷤家人——风自火出-家庭" tabindex="-1">䷤家人——风自火出（家庭） <a class="header-anchor" href="#䷤家人——风自火出-家庭" aria-label="Permalink to &quot;䷤家人——风自火出（家庭）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">离☲下巽☴上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">心火（离）生胆气（巽）——<strong>家庭和睦则心胆平衡</strong></td></tr></tbody></table><h3 id="䷥睽——上火下泽-乖离" tabindex="-1">䷥睽——上火下泽（乖离） <a class="header-anchor" href="#䷥睽——上火下泽-乖离" aria-label="Permalink to &quot;䷥睽——上火下泽（乖离）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">兑☱下离☲上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">⭐ <strong>心（离）与肺（兑）不交——气机乖离</strong></td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;">胸闷、烦热、失眠</td></tr><tr><td style="text-align:left;"><strong>普明</strong></td><td style="text-align:left;">烦躁+打鼾（气道不畅）→睽卦——心肺不和</td></tr></tbody></table><h3 id="䷦蹇——山上有水-艰难" tabindex="-1">䷦蹇——山上有水（艰难） <a class="header-anchor" href="#䷦蹇——山上有水-艰难" aria-label="Permalink to &quot;䷦蹇——山上有水（艰难）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">艮☶下坎☵上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">肾水（坎）被胃（艮）所阻——<strong>湿浊阻滞，气机不利</strong></td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;">关节痛、沉重、阴雨天加重</td></tr><tr><td style="text-align:left;"><strong>普光</strong></td><td style="text-align:left;">膝盖阴天痛→蹇卦</td></tr></tbody></table><h3 id="䷧解——雷水解-缓解" tabindex="-1">䷧解——雷水解（缓解） <a class="header-anchor" href="#䷧解——雷水解-缓解" aria-label="Permalink to &quot;䷧解——雷水解（缓解）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">坎☵下震☳上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>水（坎）中雷（震）动——寒湿得化</strong></td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;"><strong>苓桂术甘汤（温化寒湿）</strong></td></tr><tr><td style="text-align:left;"><strong>对应病机</strong></td><td style="text-align:left;">坎水得震阳而化→寒湿得解</td></tr></tbody></table><hr><h2 id="四、损益——补与泻" tabindex="-1">四、损益——补与泻 <a class="header-anchor" href="#四、损益——补与泻" aria-label="Permalink to &quot;四、损益——补与泻&quot;">​</a></h2><h3 id="䷨损——山下有泽-减损" tabindex="-1">䷨损——山下有泽（减损） <a class="header-anchor" href="#䷨损——山下有泽-减损" aria-label="Permalink to &quot;䷨损——山下有泽（减损）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">兑☱下艮☶上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>损有余——泻法的基础</strong></td></tr><tr><td style="text-align:left;"><strong>对应</strong></td><td style="text-align:left;">湿热、痰浊、瘀血→当损之</td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">承气汤（损阳明）、抵挡汤（损瘀血）</td></tr></tbody></table><h3 id="䷩益——风雷益-增益" tabindex="-1">䷩益——风雷益（增益） <a class="header-anchor" href="#䷩益——风雷益-增益" aria-label="Permalink to &quot;䷩益——风雷益（增益）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">震☳下巽☴上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>补不足——补法的基础</strong></td></tr><tr><td style="text-align:left;"><strong>对应</strong></td><td style="text-align:left;">气虚、血虚、阳虚→当益之</td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">黄芽汤（益中气）、四物汤（益肝血）</td></tr><tr><td style="text-align:left;"><strong>普光/普明</strong></td><td style="text-align:left;">普光益阳（附子）、普明益血（当归熟地）</td></tr></tbody></table><hr><h2 id="五、夬姤萃升——决断与相遇" tabindex="-1">五、夬姤萃升——决断与相遇 <a class="header-anchor" href="#五、夬姤萃升——决断与相遇" aria-label="Permalink to &quot;五、夬姤萃升——决断与相遇&quot;">​</a></h2><h3 id="䷪夬——泽上于天-决断" tabindex="-1">䷪夬——泽上于天（决断） <a class="header-anchor" href="#䷪夬——泽上于天-决断" aria-label="Permalink to &quot;䷪夬——泽上于天（决断）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">乾☰下兑☱上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">五阳决一阴——<strong>清除最后一点余邪</strong></td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">治病最后一程的&quot;扫尾&quot;</td></tr></tbody></table><h3 id="䷫姤——天下有风-相遇" tabindex="-1">䷫姤——天下有风（相遇） <a class="header-anchor" href="#䷫姤——天下有风-相遇" aria-label="Permalink to &quot;䷫姤——天下有风（相遇）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">巽☴下乾☰上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">⭐ <strong>一阴始生——夏至卦</strong></td></tr><tr><td style="text-align:left;"><strong>对应养生</strong></td><td style="text-align:left;">夏至宜静养、护一阴</td></tr></tbody></table><h3 id="䷬萃——泽上于地-聚集" tabindex="-1">䷬萃——泽上于地（聚集） <a class="header-anchor" href="#䷬萃——泽上于地-聚集" aria-label="Permalink to &quot;䷬萃——泽上于地（聚集）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">坤☷下兑☱上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">水（泽）在土（地）上——<strong>水肿、湿浊聚集</strong></td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">五苓散、真武汤</td></tr></tbody></table><h3 id="䷭升——地中生木-上升" tabindex="-1">䷭升——地中生木（上升） <a class="header-anchor" href="#䷭升——地中生木-上升" aria-label="Permalink to &quot;䷭升——地中生木（上升）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">巽☴下坤☷上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>肝木（巽）从脾土（坤）中升——清阳上升</strong></td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">补中益气汤（升清阳）、黄芽汤（升中气）</td></tr></tbody></table><hr><h2 id="六、困井革鼎——困顿与变革" tabindex="-1">六、困井革鼎——困顿与变革 <a class="header-anchor" href="#六、困井革鼎——困顿与变革" aria-label="Permalink to &quot;六、困井革鼎——困顿与变革&quot;">​</a></h2><h3 id="䷮困——泽无水-困顿" tabindex="-1">䷮困——泽无水（困顿） <a class="header-anchor" href="#䷮困——泽无水-困顿" aria-label="Permalink to &quot;䷮困——泽无水（困顿）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">坎☵下兑☱上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>水（坎）在泽（兑）下——津液不足的困顿</strong></td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;">口干舌燥、皮肤干燥、便秘</td></tr><tr><td style="text-align:left;"><strong>普光</strong></td><td style="text-align:left;">口渴+皮肤干燥→困卦</td></tr><tr><td style="text-align:left;"><strong>普明</strong></td><td style="text-align:left;">口干+便秘→困卦</td></tr></tbody></table><h3 id="䷯井——木上有水-源泉" tabindex="-1">䷯井——木上有水（源泉） <a class="header-anchor" href="#䷯井——木上有水-源泉" aria-label="Permalink to &quot;䷯井——木上有水（源泉）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">巽☴下坎☵上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>肝（巽）与肾（坎）——源泉不竭</strong></td></tr><tr><td style="text-align:left;"><strong>对应</strong></td><td style="text-align:left;">肾精充足、肝血得养</td></tr><tr><td style="text-align:left;"><strong>爻辞</strong></td><td style="text-align:left;">&quot;井渫不食，为我心恻&quot;——有井（资源）却不会用</td></tr></tbody></table><h3 id="䷰革——泽中有火-变革" tabindex="-1">䷰革——泽中有火（变革） <a class="header-anchor" href="#䷰革——泽中有火-变革" aria-label="Permalink to &quot;䷰革——泽中有火（变革）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">离☲下兑☱上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>心火（离）与肺金（兑）——变革陈旧之气</strong></td></tr><tr><td style="text-align:left;"><strong>对应</strong></td><td style="text-align:left;">大病后的体质转变</td></tr></tbody></table><h3 id="䷱鼎——火风鼎-鼎立" tabindex="-1">䷱鼎——火风鼎（鼎立） <a class="header-anchor" href="#䷱鼎——火风鼎-鼎立" aria-label="Permalink to &quot;䷱鼎——火风鼎（鼎立）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">巽☴下离☲上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>胆（巽）与心（离）——气血的运化如鼎中烹饪</strong></td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">小柴胡汤（鼎新革故）</td></tr></tbody></table><hr><h2 id="七、震艮渐归妹——动静与归位" tabindex="-1">七、震艮渐归妹——动静与归位 <a class="header-anchor" href="#七、震艮渐归妹——动静与归位" aria-label="Permalink to &quot;七、震艮渐归妹——动静与归位&quot;">​</a></h2><h3 id="䷲震——洊雷震-震动" tabindex="-1">䷲震——洊雷震（震动） <a class="header-anchor" href="#䷲震——洊雷震-震动" aria-label="Permalink to &quot;䷲震——洊雷震（震动）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">☳☳ 二雷相叠</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>肝气、惊悸、抽搐</strong></td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;">抽筋（普光）、惊悸不安</td></tr></tbody></table><h3 id="䷳艮——兼山艮-停止" tabindex="-1">䷳艮——兼山艮（停止） <a class="header-anchor" href="#䷳艮——兼山艮-停止" aria-label="Permalink to &quot;䷳艮——兼山艮（停止）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">☶☶ 二山相叠</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>胃气当降则止、肾精当藏则止</strong></td></tr><tr><td style="text-align:left;"><strong>养生</strong></td><td style="text-align:left;">&quot;君子以思不出其位&quot;——知道什么时候该停下来</td></tr></tbody></table><h3 id="䷴渐——风上山渐-渐进" tabindex="-1">䷴渐——风上山渐（渐进） <a class="header-anchor" href="#䷴渐——风上山渐-渐进" aria-label="Permalink to &quot;䷴渐——风上山渐（渐进）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">艮☶下巽☴上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">风（巽）在山（艮）上——<strong>疾病和康复都是渐进的过程</strong></td></tr></tbody></table><h3 id="䷵归妹——泽上有雷-归位" tabindex="-1">䷵归妹——泽上有雷（归位） <a class="header-anchor" href="#䷵归妹——泽上有雷-归位" aria-label="Permalink to &quot;䷵归妹——泽上有雷（归位）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">兑☱下震☳上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">⭐ <strong>肝（震）肺（兑）各归其位——左升右降的恢复</strong></td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">金鼎汤（降肺金以归位）</td></tr><tr><td style="text-align:left;"><strong>对应病机</strong></td><td style="text-align:left;"><strong>相火归位（回归坎中）</strong></td></tr></tbody></table><hr><h2 id="八、丰旅巽兑——旅途与变化" tabindex="-1">八、丰旅巽兑——旅途与变化 <a class="header-anchor" href="#八、丰旅巽兑——旅途与变化" aria-label="Permalink to &quot;八、丰旅巽兑——旅途与变化&quot;">​</a></h2><h3 id="䷶丰——雷电皆至-丰盛" tabindex="-1">䷶丰——雷电皆至（丰盛） <a class="header-anchor" href="#䷶丰——雷电皆至-丰盛" aria-label="Permalink to &quot;䷶丰——雷电皆至（丰盛）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">离☲下震☳上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">心火（离）得肝气（震）助——<strong>精神旺盛、气血丰盈</strong></td></tr></tbody></table><h3 id="䷷旅——山上有火-旅居" tabindex="-1">䷷旅——山上有火（旅居） <a class="header-anchor" href="#䷷旅——山上有火-旅居" aria-label="Permalink to &quot;䷷旅——山上有火（旅居）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">艮☶下离☲上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>胃（艮）与心（离）——旅居在外则水土不服</strong></td></tr><tr><td style="text-align:left;"><strong>普光/普明</strong></td><td style="text-align:left;">从山东/湖北迁居大理→旅卦—适应新环境的调养</td></tr></tbody></table><h3 id="䷸巽——随风巽-顺入" tabindex="-1">䷸巽——随风巽（顺入） <a class="header-anchor" href="#䷸巽——随风巽-顺入" aria-label="Permalink to &quot;䷸巽——随风巽（顺入）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">☴☴ 二风相叠</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>胆气疏泄、如风入物</strong></td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;">口苦、胆怯</td></tr></tbody></table><h3 id="䷹兑——丽泽兑-喜悦" tabindex="-1">䷹兑——丽泽兑（喜悦） <a class="header-anchor" href="#䷹兑——丽泽兑-喜悦" aria-label="Permalink to &quot;䷹兑——丽泽兑（喜悦）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">☱☱ 二泽相叠</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>喜悦——肺气通调、营卫和谐</strong></td></tr><tr><td style="text-align:left;"><strong>健康</strong></td><td style="text-align:left;">喜则气和——保持心情愉悦是最好的药</td></tr></tbody></table><hr><h2 id="九、涣节中孚小过——调与节" tabindex="-1">九、涣节中孚小过——调与节 <a class="header-anchor" href="#九、涣节中孚小过——调与节" aria-label="Permalink to &quot;九、涣节中孚小过——调与节&quot;">​</a></h2><h3 id="䷺涣——风行水上-散开" tabindex="-1">䷺涣——风行水上（散开） <a class="header-anchor" href="#䷺涣——风行水上-散开" aria-label="Permalink to &quot;䷺涣——风行水上（散开）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">坎☵下巽☴上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>风（巽）吹水（坎）——湿浊得散</strong></td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;"><strong>越婢汤（发汗散水）、五苓散（利水）</strong></td></tr></tbody></table><h3 id="䷻节——泽上有水-节制" tabindex="-1">䷻节——泽上有水（节制） <a class="header-anchor" href="#䷻节——泽上有水-节制" aria-label="Permalink to &quot;䷻节——泽上有水（节制）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">兑☱下坎☵上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">⭐ <strong>节卦=养生的核心——食饮有节、起居有常</strong></td></tr><tr><td style="text-align:left;"><strong>爻辞</strong></td><td style="text-align:left;">&quot;苦节不可贞&quot;——过度的节制也不行</td></tr><tr><td style="text-align:left;"><strong>普光/普明</strong></td><td style="text-align:left;">饮食健康、睡眠规律→已有节卦基础</td></tr></tbody></table><h3 id="䷼中孚——泽上有风-诚信" tabindex="-1">䷼中孚——泽上有风（诚信） <a class="header-anchor" href="#䷼中孚——泽上有风-诚信" aria-label="Permalink to &quot;䷼中孚——泽上有风（诚信）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">兑☱下巽☴上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>肺（兑）与胆（巽）——气机的流畅需要&quot;信&quot;</strong></td></tr><tr><td style="text-align:left;"><strong>对应养生</strong></td><td style="text-align:left;">信任身体的自愈力</td></tr></tbody></table><h3 id="䷽小过——山上有雷-小过" tabindex="-1">䷽小过——山上有雷（小过） <a class="header-anchor" href="#䷽小过——山上有雷-小过" aria-label="Permalink to &quot;䷽小过——山上有雷（小过）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">艮☶下震☳上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;"><strong>小有过失——疾病初起、微调即可</strong></td></tr><tr><td style="text-align:left;"><strong>对应养生</strong></td><td style="text-align:left;">治未病——小过时纠正，不等到大过</td></tr></tbody></table><hr><h2 id="十、既济未济——最终的结局" tabindex="-1">十、既济未济——最终的结局 <a class="header-anchor" href="#十、既济未济——最终的结局" aria-label="Permalink to &quot;十、既济未济——最终的结局&quot;">​</a></h2><h3 id="䷾既济——水在火上-成功" tabindex="-1">䷾既济——水在火上（成功） <a class="header-anchor" href="#䷾既济——水在火上-成功" aria-label="Permalink to &quot;䷾既济——水在火上（成功）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">离☲下坎☵上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">⭐ <strong>水火既济——人体最理想的状态！</strong></td></tr><tr><td style="text-align:left;"><strong>含义</strong></td><td style="text-align:left;">火（心）在下→能温肾水；水（肾）在上→能制心火</td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;">无——这是健康态</td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">所有处方的最终目标——<strong>泰+既济</strong></td></tr></tbody></table><h3 id="䷿未济——火在水上-未完成" tabindex="-1">䷿未济——火在水上（未完成） <a class="header-anchor" href="#䷿未济——火在水上-未完成" aria-label="Permalink to &quot;䷿未济——火在水上（未完成）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦象</th><th style="text-align:left;">坎☵下离☲上</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>医理</strong></td><td style="text-align:left;">⭐ <strong>水火未济——人体的疾病态！</strong></td></tr><tr><td style="text-align:left;"><strong>含义</strong></td><td style="text-align:left;">火（心）在上→上热；水（肾）在下→下寒</td></tr><tr><td style="text-align:left;"><strong>对应症状</strong></td><td style="text-align:left;"><strong>上热下寒</strong>（普光+普明共同的格局）</td></tr><tr><td style="text-align:left;"><strong>对应方</strong></td><td style="text-align:left;">温潜黄芽天魂汤（普光）、加减黄芽地魄汤（普明）</td></tr></tbody></table><hr><h2 id="普光、普明的下经卦象诊断总表" tabindex="-1">普光、普明的下经卦象诊断总表 <a class="header-anchor" href="#普光、普明的下经卦象诊断总表" aria-label="Permalink to &quot;普光、普明的下经卦象诊断总表&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">卦</th><th style="text-align:left;">普光</th><th style="text-align:left;">普明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>咸䷞</strong></td><td style="text-align:left;">—</td><td style="text-align:left;">⭐ 心肾不交→失眠</td></tr><tr><td style="text-align:left;"><strong>恒䷟</strong></td><td style="text-align:left;">坚持站桩+服药</td><td style="text-align:left;">坚持静坐+休养</td></tr><tr><td style="text-align:left;"><strong>大壮䷡</strong></td><td style="text-align:left;">血压高→雷在天上</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;"><strong>明夷䷣</strong></td><td style="text-align:left;">⭐ 热被湿困→口渴不贪凉</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;"><strong>睽䷥</strong></td><td style="text-align:left;">—</td><td style="text-align:left;">⭐ 心肺不和→烦躁打鼾</td></tr><tr><td style="text-align:left;"><strong>蹇䷦</strong></td><td style="text-align:left;">⭐ 阴雨天膝痛</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;"><strong>解䷧</strong></td><td style="text-align:left;">苓桂术甘→普光寒湿</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;"><strong>损益</strong></td><td style="text-align:left;">损湿热(泽柏)+益阳气(附)</td><td style="text-align:left;">损郁火+益气血</td></tr><tr><td style="text-align:left;"><strong>夬䷪</strong></td><td style="text-align:left;">清除湿浊最后一程</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;"><strong>困䷮</strong></td><td style="text-align:left;">⭐ 口渴皮干</td><td style="text-align:left;">⭐ 口干便秘</td></tr><tr><td style="text-align:left;"><strong>节䷻</strong></td><td style="text-align:left;">已有基础</td><td style="text-align:left;">午休应加强</td></tr><tr><td style="text-align:left;"><strong>既济䷾</strong></td><td style="text-align:left;"><strong>目标：水火既济</strong></td><td style="text-align:left;"><strong>目标：水火既济</strong></td></tr><tr><td style="text-align:left;"><strong>未济䷿</strong></td><td style="text-align:left;">⭐ <strong>当前状态</strong></td><td style="text-align:left;">⭐ <strong>当前状态</strong></td></tr></tbody></table><hr><h2 id="六十四卦人体对应总结" tabindex="-1">六十四卦人体对应总结 <a class="header-anchor" href="#六十四卦人体对应总结" aria-label="Permalink to &quot;六十四卦人体对应总结&quot;">​</a></h2><blockquote><p><strong>上经三十卦：讲天道——对应人体的先天体质、根本功能</strong><strong>下经三十四卦：讲人道——对应人的疾病、情绪、人际关系</strong></p></blockquote><p><strong>上经+下经 = 完整的&quot;人体生命模型&quot;</strong></p><p><strong>普光/普明的治疗目标</strong>： 从<strong>未济䷿</strong>（火在水上→上热下寒） ⬇ 经过<strong>泰䷊</strong>（天地交泰→阴阳通调） ⬇ 最终<strong>既济䷾</strong>（水火既济→人体平衡）</p><hr><p><em>下经三十四卦完。与上经三十卦合为六十四卦完整体系。二者可相互参照、全面应诊。</em></p>',103)])])}const f=e(n,[["render",d]]);export{y as __pageData,f as default};
